import { getContext, setContext } from 'svelte';
import { browser } from '$app/environment';
import type { ComprasState, Paquete, NivelConfig, BitacoraEntry } from './types';
import { createInitialComprasState } from './seed';

const STORAGE_KEY = 'tps-compras-state';
const DATA_VERSION = 1;

function loadState(): ComprasState | null {
	if (!browser) return null;
	try {
		const raw = localStorage.getItem(STORAGE_KEY);
		if (!raw) return null;
		const parsed = JSON.parse(raw);
		if (parsed._dataVersion !== DATA_VERSION || !parsed.paquetes || !parsed.requisiciones) {
			localStorage.removeItem(STORAGE_KEY);
			return null;
		}
		return parsed as ComprasState;
	} catch {
		return null;
	}
}

